function i(r){return r.replace(/[^a-zA-Z0-9]/g,"").toUpperCase()}function s(r){let e=i(r);if(e.length<15||e.length>34||!/^[A-Z]{2}\d{2}[A-Z0-9]+$/.test(e))return!1;let o=e.slice(4)+e.slice(0,4),t=0;for(let n of o)if(/\d/.test(n))t=(t*10+Number(n))%97;else{let a=n.charCodeAt(0)-55;t=(t*100+a)%97}return t===1}function c(r){if(!r)return"\u2014";if(r.includes("*"))return r;let e=i(r);return e.length<=4?"*".repeat(e.length):`********${e.slice(-4)}`}export{i as a,s as b,c};
